sections.code_example:
word = "Python"

for i, char in enumerate(word):
    print(i, "->", char)

# You can start the index at 1 if you prefer
for i, char in enumerate(word, start=1):
    print(i, char)

exercises.solution:
items = ["milk", "eggs", "bread"]

for item in items:
    print("-", item)

colors = ["red", "green", "blue"]

for i, color in enumerate(colors, start=1):
    print(str(i) + ". " + color)
